"use client";

import {
  Activity,
  Bell,
  LogOut,
  Menu,
  UserCircle,
} from "lucide-react";
import { useEffect, useState } from "react";

import AcademicYearSwitcher from "./AcademicYearSwitcher";
import BrandLogo from "./BrandLogo";
import GlobalSearch from "./GlobalSearch";
import SchoolSwitcher from "./SchoolSwitcher";

type HeaderUser = {
  full_name?: string;
  role?: string;
};

type HeaderSchool = {
  school_name?: string;
  schoolName?: string;
  logoUrl?: string;
  product?: string;
  secondaryColor?: string;
};

const readStoredHeaderUser = () => {
  if (typeof window === "undefined") {
    return null;
  }

  try {
    const storedUser =
      localStorage.getItem("erpUser");

    return storedUser
      ? (JSON.parse(
          storedUser
        ) as HeaderUser)
      : null;
  } catch {
    return null;
  }
};

export default function Header({
  onOpenMenu,
}: {
  onOpenMenu?: () => void;
}) {
  const [user] =
    useState<HeaderUser | null>(
      readStoredHeaderUser
    );
  const [school, setSchool] =
    useState<HeaderSchool | null>(
      null
    );

  useEffect(() => {
    let active = true;
    const loadBranding = () => {
      fetch(
        `/api/my-school-branding?t=${Date.now()}`,
        {
          cache: "no-store",
        }
      )
        .then((response) =>
          response.json()
        )
        .then((data) => {
          if (active) {
            setSchool(data);
          }
        })
        .catch(console.error);
    };

    loadBranding();
    window.addEventListener(
      "tottech-branding-updated",
      loadBranding
    );

    return () => {
      active = false;
      window.removeEventListener(
        "tottech-branding-updated",
        loadBranding
      );
    };
  }, []);

  const logout = async () => {
    try {
      await fetch(
        "/api/auth/logout",
        {
          method: "POST",
        }
      );

      localStorage.removeItem(
        "erpUser"
      );

      window.location.href =
        "/login";
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <div
      className="
        sticky
        top-0
        z-40
        border-b
        border-slate-200
        bg-white/95
        backdrop-blur-xl
      "
    >
      <div
        className="
          hidden
          min-h-[86px]
          grid-cols-[minmax(280px,320px)_minmax(180px,1fr)_auto]
          items-center
          gap-4
          px-5
          md:grid
          lg:grid-cols-[minmax(320px,360px)_minmax(240px,1fr)_auto]
          xl:grid-cols-[minmax(340px,390px)_minmax(340px,1fr)_auto]
          xl:px-7
        "
      >
        <div className="flex min-w-0 flex-col items-start gap-1">
          <BrandLogo
            variant="full"
            orientation="horizontal"
            logoUrl={school?.logoUrl}
            name="TOTTECH ONE"
            imageClassName="h-[52px] w-[66px] shrink-0 rounded-xl object-contain object-center shadow-sm lg:h-[62px] lg:w-[78px]"
            nameClassName="max-w-[205px] truncate text-left text-[19px] lg:max-w-[235px] lg:text-[23px]"
          />

          <div className="min-w-0 pl-[74px] lg:pl-[88px]">
            <p
              className="
                truncate
                text-xs
                font-semibold
                text-slate-600
              "
              title={
                school?.schoolName ||
                school?.school_name ||
                "No school selected"
              }
            >
              {school?.schoolName ||
                school?.school_name ||
                "No school selected"}
            </p>
          </div>
        </div>

        <div className="flex min-w-0 items-center gap-3">
          <div className="min-w-0 flex-1">
            <GlobalSearch />
          </div>

          <div className="hidden shrink-0 md:block">
            <AcademicYearSwitcher />
          </div>
        </div>

        <div
          className="
            flex
            min-w-0
            shrink-0
            items-center
            justify-end
            gap-3
          "
        >
          <div className="hidden w-[180px] md:block lg:w-[210px] xl:w-[260px]">
            <SchoolSwitcher />
          </div>

          <DesktopUserSection
            user={user}
            logout={logout}
          />
        </div>
      </div>

      <div
        className="
          px-4
          py-3
          md:hidden
        "
      >
        <div className="mb-3 flex min-w-0 items-center justify-between gap-3">
          <button
            onClick={onOpenMenu}
            className="
              grid
              h-11
              w-11
              shrink-0
              place-items-center
              rounded-lg
              border
              border-slate-200
              bg-white
              text-slate-950
              shadow-sm
              active:scale-95
            "
            aria-label="Open menu"
          >
            <Menu size={21} />
          </button>

          <div className="flex min-w-0 flex-1 items-center gap-3">
            <div className="min-w-0 flex-1 overflow-hidden">
              <BrandLogo
                variant="full"
                orientation="horizontal"
                logoUrl={school?.logoUrl}
                name="TOTTECH ONE"
                imageClassName="h-[48px] w-[60px] shrink-0 rounded-xl object-contain object-center shadow-sm"
                nameClassName="max-w-[180px] truncate text-left text-[18px]"
              />
              <p className="truncate text-xs font-medium text-amber-700">
                {school?.schoolName ||
                  school?.school_name ||
                  "School"}
              </p>
            </div>
          </div>

          <button
            onClick={logout}
            className="
              grid
              h-10
              w-10
              shrink-0
              place-items-center
              rounded-lg
              bg-slate-950
              text-white
            "
            aria-label="Logout"
          >
            <LogOut size={17} />
          </button>
        </div>

        <div className="mb-3 grid grid-cols-2 gap-2">
          <AcademicYearSwitcher compact />
          <SchoolSwitcher />
        </div>

        <GlobalSearch />
      </div>
    </div>
  );
}

function DesktopUserSection({
  user,
  logout,
}: {
  user: HeaderUser | null;
  logout: () => void;
}) {
  const initial =
    user?.full_name
      ? String(user.full_name)
          .charAt(0)
          .toUpperCase()
      : "T";

  return (
    <div
      className="
        flex
        shrink-0
        items-center
        gap-2
        whitespace-nowrap
      "
    >
      <div
        className="
          flex
          h-10
          items-center
          gap-1.5
          rounded-lg
          border
          border-amber-200
          bg-amber-50
          px-3
          text-xs
          font-bold
          text-amber-800
        "
      >
        <Activity size={15} />
        Health 87
      </div>

      <button
        className="
          relative
          grid
          h-10
          w-10
          place-items-center
          rounded-lg
          bg-slate-100
          text-slate-950
        "
        aria-label="Notifications"
      >
        <Bell size={17} />
        <span
          className="
            absolute
            right-1
            top-1
            h-2
            w-2
            rounded-full
            bg-amber-600
          "
        />
      </button>

      <div
        className="
          hidden
          min-w-0
          max-w-[128px]
          text-right
          xl:block
        "
      >
        <p
          className="
            truncate
            text-sm
            font-bold
            leading-5
            text-slate-950
          "
        >
          {user?.full_name ||
            "Administrator"}
        </p>

        <p
          className="
            truncate
            text-[11px]
            font-semibold
            uppercase
            text-slate-500
          "
        >
          {user?.role || "ADMIN"}
        </p>
      </div>

      <div
        className="
          grid
          h-10
          w-10
          shrink-0
          place-items-center
          rounded-lg
          border
          border-amber-300/70
          bg-slate-950
          shadow-sm
          text-sm
          font-black
          leading-none
          text-amber-100
        "
        aria-label="Current user avatar"
        title={
          user?.full_name ||
          "Administrator"
        }
      >
        <span>
          {initial || (
            <UserCircle
              size={18}
              className="text-amber-100"
            />
          )}
        </span>
      </div>

      <button
        onClick={logout}
        className="
          flex
          h-10
          items-center
          gap-2
          rounded-lg
          border
          border-slate-200
          bg-white
          px-3
          text-sm
          font-bold
          text-slate-950
          shadow-sm
          hover:bg-slate-50
        "
      >
        <LogOut size={16} />
        <span className="hidden xl:inline">
          Logout
        </span>
      </button>
    </div>
  );
}
