"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import type { ReactNode } from "react";
import {
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react";
import { hasPermission } from "@/lib/auth/hasPermission";
import TottechAIBadge from "./ai/TottechAIBadge";
import BrandLogo from "./BrandLogo";

import {
  Bell,
  BookOpen,
  Building2,
  Bus,
  ChevronDown,
  ChevronRight,
  ClipboardList,
  GraduationCap,
  Home,
  LayoutDashboard,
  Rocket,
  Settings,
  ShieldCheck,
  Sparkles,
  Utensils,
  Users,
  Wallet,
} from "lucide-react";

type UserProfile = {
  role: string;
  full_name?: string;
  module_access?: Record<string, boolean>;
  user_module_access?: Record<string, boolean>;
};

type SidebarBranding = {
  schoolName?: string;
  product?: string;
  logoUrl?: string;
  aiDisplayName?: string;
  aiTagline?: string;
};

type MenuItemProps = {
  pathname: string;
  href: string;
  label: string;
  icon?: ReactNode;
  onNavigate?: () => void;
};

type SectionButtonProps = {
  title: string;
  icon: ReactNode;
  open: boolean;
  setOpen: (value: boolean) => void;
};

const normalizeRole = (
  role?: string
) =>
  role
    ?.toUpperCase()
    .replaceAll(" ", "_") || "";

const readStoredUser = () => {
  if (typeof window === "undefined") {
    return null;
  }

  try {
    const storedUser =
      localStorage.getItem("erpUser");

    return storedUser
      ? (JSON.parse(
          storedUser
        ) as UserProfile)
      : null;
  } catch {
    return null;
  }
};

export default function Sidebar({
  onNavigate,
}: {
  onNavigate?: () => void;
}) {
  const pathname =
    usePathname();
  const navRef = useRef<HTMLElement | null>(null);
  const [user] =
    useState<UserProfile | null>(
      readStoredUser
    );
  const [branding, setBranding] =
    useState<SidebarBranding | null>(
      null
    );
  const [academicsOpen, setAcademicsOpen] =
    useState(
      () =>
        pathname.startsWith(
          "/academics"
        ) ||
        pathname.startsWith(
          "/promotions"
        )
    );
  const [financeOpen, setFinanceOpen] =
    useState(
      () =>
        pathname.startsWith(
          "/finance"
        )
    );
  const [operationsOpen, setOperationsOpen] =
    useState(
      () =>
        pathname.startsWith(
          "/attendance"
        ) ||
        pathname.startsWith(
          "/transport"
        ) ||
        pathname.startsWith("/hostel") ||
        pathname.startsWith("/dining")
    );
  const [aiOpen, setAiOpen] =
    useState(false);
  const [parentOpen, setParentOpen] =
    useState(false);
  const [moduleAccess, setModuleAccess] =
    useState<Record<string, boolean>>(
      () => user?.module_access || {}
    );
  const [userModuleAccess, setUserModuleAccess] =
    useState<Record<string, boolean>>(
      () => user?.user_module_access || {}
    );

  useEffect(() => {
    let active = true;
    const loadBranding = () => {
      fetch(
        `/api/my-school-branding?t=${Date.now()}`,
        {
          cache: "no-store",
        }
      )
        .then((response) =>
          response.json()
        )
        .then((data) => {
          if (active) {
            setBranding(data);
          }
        })
        .catch(console.error);
    };

    loadBranding();
    window.addEventListener(
      "tottech-branding-updated",
      loadBranding
    );

    return () => {
      active = false;
      window.removeEventListener(
        "tottech-branding-updated",
        loadBranding
      );
    };
  }, []);

  useEffect(() => {
    let active = true;

    fetch("/api/school-context", {
      cache: "no-store",
    })
      .then((response) =>
        response.ok
          ? response.json()
          : null
      )
      .then((data) => {
        if (active && data?.moduleAccess) {
          setModuleAccess(data.moduleAccess);
          if (data.userModuleAccess) {
            setUserModuleAccess(data.userModuleAccess);
          }
          try {
            const stored = readStoredUser();
            if (stored) {
              localStorage.setItem(
                "erpUser",
                JSON.stringify({
                  ...stored,
                  module_access:
                    {
                      ...data.moduleAccess,
                      ...(data.userModuleAccess || {}),
                    },
                  user_module_access:
                    data.userModuleAccess || {},
                })
              );
            }
          } catch {
            // local storage is best effort only
          }
        }
      })
      .catch(() => {});

    return () => {
      active = false;
    };
  }, []);

  useEffect(() => {
    if (
      pathname.startsWith("/academics") ||
      pathname.startsWith("/promotions")
    ) {
      setAcademicsOpen(true);
    }

    if (pathname.startsWith("/finance")) {
      setFinanceOpen(true);
    }

    if (
      pathname.startsWith("/attendance") ||
      pathname.startsWith("/transport") ||
      pathname.startsWith("/hostel") ||
      pathname.startsWith("/dining")
    ) {
      setOperationsOpen(true);
    }

    if (pathname.startsWith("/parent")) {
      setParentOpen(true);
    }

    if (
      pathname.startsWith("/ai-") ||
      pathname.startsWith("/school-brain") ||
      pathname.startsWith("/student-intelligence") ||
      pathname.startsWith("/faculty-intelligence")
    ) {
      setAiOpen(true);
    }

    const timers = [
      window.setTimeout(() => {
        navRef.current
          ?.querySelector<HTMLElement>(
            '[data-sidebar-active-menu="true"]'
          )
          ?.scrollIntoView({
            behavior: "smooth",
            block: "center",
            inline: "nearest",
          });
      }, 80),
      window.setTimeout(() => {
        navRef.current
          ?.querySelector<HTMLElement>(
            '[data-sidebar-active-menu="true"]'
          )
          ?.scrollIntoView({
            behavior: "smooth",
            block: "center",
            inline: "nearest",
          });
      }, 260),
    ];

    return () =>
      timers.forEach((timer) =>
        window.clearTimeout(timer)
      );
  }, [pathname]);

  const role =
    normalizeRole(user?.role);

  const dashboardHref =
    useMemo(() => {
      if (role === "PARENT") {
        return "/parent/dashboard";
      }

      if (role === "TEACHER") {
        return "/dashboard/teacher";
      }

      if (role === "PRINCIPAL") {
        return "/dashboard/principal";
      }

      return "/";
    }, [role]);

  const can = (permission: string) =>
    Boolean(
      role && hasPermission(role, permission)
    );

  const isExecutive =
    role === "SUPER_ADMIN" ||
    role === "PRINCIPAL";
  const isSchoolAdmin =
    role === "SUPER_ADMIN" ||
    role === "OWNER" ||
    role === "ADMIN";

  const isParent =
    role === "PARENT";
  const hasModule = (moduleKey: string) =>
    role === "SUPER_ADMIN" ||
    (moduleAccess[moduleKey] !== false &&
      userModuleAccess[moduleKey] !== false);

  const canAcademics =
    hasModule("ACADEMICS") &&
    (isExecutive ||
    can("academics") ||
    can("classes") ||
    can("sections") ||
    can("subjects") ||
    can("timetable") ||
    can("exams") ||
    can("exam_schedule") ||
    can("question_bank") ||
    can("question_papers") ||
    can("homework") ||
    can("marks") ||
    can("marks_entry"));

  const canDining =
    hasModule("DINING") &&
    (isExecutive || can("dining"));

  const canOperations =
    hasModule("OPERATIONS") &&
    (isExecutive ||
    can("operations") ||
    can("attendance") ||
    can("transport") ||
    can("hostel") ||
    canDining);

  return (
    <aside className="flex h-screen w-[240px] flex-col overflow-y-auto border-r border-white/10 bg-[#101a2c] text-white shadow-[0_0_60px_rgba(15,23,42,0.25)] lg:w-[280px]">
      <div className="min-w-0 border-b border-white/10 px-4 py-5 lg:px-5 lg:py-6">
        <Link
          href={dashboardHref}
          onClick={onNavigate}
          className="flex min-w-0 flex-col items-center gap-3 overflow-hidden rounded-2xl bg-white/[0.03] px-3 py-4"
        >
          <BrandLogo
            variant="full"
            logoUrl={
              branding?.logoUrl
            }
            name={branding?.product || "TOTTECH ONE"}
            imageClassName="h-[92px] w-[136px] rounded-2xl object-contain object-center shadow-[0_18px_45px_rgba(245,158,11,0.16)] lg:h-[112px] lg:w-[164px]"
            nameClassName="max-w-full whitespace-normal px-1 text-[23px] lg:text-[28px]"
          />
          <span
            className="block max-w-full truncate px-2 text-center text-xs font-bold text-white/75"
            title={branding?.schoolName || "School workspace"}
          >
            {branding?.schoolName || "School workspace"}
          </span>
        </Link>

        <div className="mt-5 min-w-0 rounded-2xl border border-white/10 bg-white/5 p-4">
          <div className="flex items-center gap-2 text-xs font-bold uppercase tracking-[0.16em] text-white/45">
            <Sparkles size={14} />
            Workspace
          </div>
          <div
            className="mt-2 truncate text-sm font-bold text-white"
            title={user?.full_name || "School Team"}
          >
            {user?.full_name || "School Team"}
          </div>
          <div
            className="mt-1 truncate text-xs font-semibold text-white/50"
            title={
              role.replaceAll("_", " ") ||
              "Protected"
            }
          >
            {role.replaceAll("_", " ") ||
              "Protected"}
          </div>
        </div>
      </div>

      <nav
        ref={navRef}
        className="flex-1 space-y-2 p-4 scroll-smooth"
      >
        <MenuItem
          pathname={pathname}
          href={dashboardHref}
          icon={<LayoutDashboard size={18} />}
          label="Dashboard"
          onNavigate={onNavigate}
        />

        {hasModule("STUDENTS") && can("students") && (
          <MenuItem
            pathname={pathname}
            href="/students/list"
            icon={<GraduationCap size={18} />}
            label="Students"
            onNavigate={onNavigate}
          />
        )}

        {hasModule("TEACHERS") && can("teachers") && (
          <MenuItem
            pathname={pathname}
            href="/teachers"
            icon={<Users size={18} />}
            label="Teachers"
            onNavigate={onNavigate}
          />
        )}

        {canAcademics && (
          <>
            <SectionButton
              title="Academics"
              icon={<BookOpen size={18} />}
              open={academicsOpen}
              setOpen={setAcademicsOpen}
            />
            {academicsOpen && (
              <div className="ml-4 space-y-1 border-l border-white/10 pl-4">
                <MenuItem
                  pathname={pathname}
                  href="/academics/classes"
                  label="Classes"
                  onNavigate={onNavigate}
                />
                <MenuItem
                  pathname={pathname}
                  href="/academics/exam-schedule"
                  label="Exam Schedule"
                  onNavigate={onNavigate}
                />
                <MenuItem
                  pathname={pathname}
                  href="/academics/exams"
                  label="Exams"
                  onNavigate={onNavigate}
                />
                <MenuItem
                  pathname={pathname}
                  href="/academics/homework"
                  label="Homework"
                  onNavigate={onNavigate}
                />
                <MenuItem
                  pathname={pathname}
                  href="/academics/marks-entry"
                  label="Marks Entry"
                  onNavigate={onNavigate}
                />
                <MenuItem
                  pathname={pathname}
                  href="/academics/question-bank"
                  label="Question Bank"
                  onNavigate={onNavigate}
                />
                <MenuItem
                  pathname={pathname}
                  href="/academics/question-papers"
                  label="Question Papers"
                  onNavigate={onNavigate}
                />
                <MenuItem
                  pathname={pathname}
                  href="/academics/sections"
                  label="Sections"
                  onNavigate={onNavigate}
                />
                <MenuItem
                  pathname={pathname}
                  href="/academics/syllabus"
                  label="Syllabus"
                  onNavigate={onNavigate}
                />
                <MenuItem
                  pathname={pathname}
                  href="/academics/subjects"
                  label="Subjects"
                  onNavigate={onNavigate}
                />
                <MenuItem
                  pathname={pathname}
                  href="/academics/timetable"
                  label="Timetable"
                  onNavigate={onNavigate}
                />
              </div>
            )}
          </>
        )}

        {hasModule("AI") && (isExecutive || isSchoolAdmin || role === "TEACHER") && (
          <>
            <SectionButton
              title={
                branding?.aiDisplayName ||
                "School Assistant"
              }
              icon={<TottechAIBadge size="sm" />}
              open={aiOpen}
              setOpen={setAiOpen}
            />
            {aiOpen && (
              <div className="ml-4 space-y-1 border-l border-white/10 pl-4">
                <MenuItem
                  pathname={pathname}
                  href="/ai-command-center"
                  label="AI Command Center"
                  onNavigate={onNavigate}
                />
                <MenuItem
                  pathname={pathname}
                  href="/ai-school-copilot"
                  label={
                    branding?.aiDisplayName ||
                    "School Assistant"
                  }
                  onNavigate={onNavigate}
                />
                <MenuItem
                  pathname={pathname}
                  href="/faculty-intelligence"
                  label="Faculty Intelligence"
                  onNavigate={onNavigate}
                />
                <MenuItem
                  pathname={pathname}
                  href="/student-intelligence"
                  label="Student Intelligence"
                  onNavigate={onNavigate}
                />
              </div>
            )}
          </>
        )}

        {hasModule("FINANCE") && can("finance") && (
          <>
            <MenuItem
              pathname={pathname}
              href="/finance"
              icon={<Wallet size={18} />}
              label="Finance"
              onNavigate={onNavigate}
            />
          </>
        )}

        {canOperations && (
          <SectionButton
            title="Operations"
            icon={<Bus size={18} />}
            open={operationsOpen}
            setOpen={setOperationsOpen}
          />
        )}
        {canOperations && operationsOpen && (
          <div className="ml-4 space-y-1 border-l border-white/10 pl-4">
            {hasModule("OPERATIONS") &&
              (isExecutive ||
                can("attendance")) && (
                <>
                  <MenuItem
                    pathname={pathname}
                    href="/attendance"
                    label="Attendance"
                    onNavigate={onNavigate}
                  />
                  <MenuItem
                    pathname={pathname}
                    href="/attendance/calendar"
                    label="Attendance Calendar"
                    onNavigate={onNavigate}
                  />
                </>
              )}
            {canDining && (
              <MenuItem
                pathname={pathname}
                href="/dining"
                icon={<Utensils size={16} />}
                label="Dining"
                onNavigate={onNavigate}
              />
            )}
            {hasModule("HOSTEL") &&
              (isExecutive ||
                can("hostel")) && (
                <MenuItem
                  pathname={pathname}
                  href="/hostel"
                  label="Hostel"
                  onNavigate={onNavigate}
                />
              )}
            {hasModule("TRANSPORT") &&
              (isExecutive ||
                can("transport")) && (
                <MenuItem
                  pathname={pathname}
                  href="/transport"
                  label="Transport"
                  onNavigate={onNavigate}
                />
              )}
          </div>
        )}

        {role === "ACCOUNTANT" && hasModule("REPORTS") && (
          <MenuItem
            pathname={pathname}
            href="/reports"
            icon={<ClipboardList size={18} />}
            label="Reports Center"
            onNavigate={onNavigate}
          />
        )}

        {(isExecutive || role === "ADMIN" || role === "OWNER") &&
          hasModule("ANALYTICS") && (
            <>
              <MenuItem
                pathname={pathname}
                href="/principal-analytics"
                icon={<Rocket size={18} />}
                label="Principal Analytics"
                onNavigate={onNavigate}
              />
              {hasModule("REPORTS") && (
                <MenuItem
                  pathname={pathname}
                  href="/reports"
                  icon={<ClipboardList size={18} />}
                  label="Reports Center"
                  onNavigate={onNavigate}
                />
              )}
            </>
          )}

        {isParent && hasModule("PARENT_PORTAL") && (
          <>
            <SectionButton
              title="Parent Portal"
              icon={<Home size={18} />}
              open={parentOpen}
              setOpen={setParentOpen}
            />
            {parentOpen && (
              <div className="ml-4 space-y-1 border-l border-white/10 pl-4">
                <MenuItem
                  pathname={pathname}
                  href="/parent/dashboard"
                  label="Overview"
                  onNavigate={onNavigate}
                />
                <MenuItem
                  pathname={pathname}
                  href="/parent/attendance"
                  label="Attendance"
                  onNavigate={onNavigate}
                />
                <MenuItem
                  pathname={pathname}
                  href="/parent/attendance-declaration"
                  label="Attendance Declaration"
                  onNavigate={onNavigate}
                />
                <MenuItem
                  pathname={pathname}
                  href="/parent/fees"
                  label="Fees"
                  onNavigate={onNavigate}
                />
                <MenuItem
                  pathname={pathname}
                  href="/parent/marks"
                  label="Marks"
                  onNavigate={onNavigate}
                />
              </div>
            )}
          </>
        )}

        {!isParent && (
          <MenuItem
            pathname={pathname}
            href="/communication"
            icon={<Bell size={18} />}
            label="Communication"
            onNavigate={onNavigate}
          />
        )}

        {role !== "SUPER_ADMIN" &&
          isSchoolAdmin &&
          hasModule("USER_MANAGEMENT") && (
            <MenuItem
              pathname={pathname}
              href="/settings/users"
              icon={<ShieldCheck size={18} />}
              label="User Management"
              onNavigate={onNavigate}
            />
          )}

        {role === "SUPER_ADMIN" && (
          <>
            <MenuItem
              pathname={pathname}
              href="/schools/list"
              icon={<Building2 size={18} />}
              label="Schools"
              onNavigate={onNavigate}
            />
            <MenuItem
              pathname={pathname}
              href="/settings/users"
              icon={<ShieldCheck size={18} />}
              label="User Management"
              onNavigate={onNavigate}
            />
            <MenuItem
              pathname={pathname}
              href="/platform/subscriptions"
              icon={<ShieldCheck size={18} />}
              label="School Governance"
              onNavigate={onNavigate}
            />
            <MenuItem
              pathname={pathname}
              href="/settings"
              icon={<Settings size={18} />}
              label="Settings"
              onNavigate={onNavigate}
            />
          </>
        )}
      </nav>

      <div className="border-t border-white/10 p-4">
        {hasModule("AI") && (
          <Link
            href="/ai-school-copilot"
            onClick={onNavigate}
            className="flex items-center gap-3 rounded-lg border border-amber-300/40 bg-amber-300/15 p-4 text-sm font-bold text-amber-50 shadow-[0_14px_40px_rgba(245,158,11,0.12)] transition hover:bg-amber-300/20"
          >
            <TottechAIBadge size="sm" />
            <span className="min-w-0">
              <span className="block truncate">
                Ask{" "}
                {branding?.aiDisplayName ||
                  "School Assistant"}
              </span>
              <span className="block truncate text-[11px] font-bold uppercase tracking-[0.12em] text-amber-200">
                {branding?.aiTagline ||
                  "School Copilot"}
              </span>
            </span>
          </Link>
        )}
      </div>
    </aside>
  );
}

function MenuItem({
  pathname,
  href,
  label,
  icon,
  onNavigate,
}: MenuItemProps) {
  const active =
    pathname === href ||
    (href !== "/" &&
      pathname.startsWith(`${href}/`));

  return (
    <Link
      href={href}
      onClick={onNavigate}
      data-sidebar-active-menu={
        active ? "true" : undefined
      }
      className={`flex min-w-0 items-center gap-3 rounded-lg px-4 py-3 text-sm font-bold transition-all duration-200 ${
        active
          ? "bg-white text-slate-950 shadow-lg"
          : "text-slate-200 hover:bg-white/10 hover:text-white"
      }`}
      title={label}
    >
      {icon && (
        <span
          className={`shrink-0 ${
            active
              ? "text-amber-700"
              : "text-slate-300"
          }`}
        >
          {icon}
        </span>
      )}
      <span className="min-w-0 truncate">{label}</span>
    </Link>
  );
}

function SectionButton({
  title,
  icon,
  open,
  setOpen,
}: SectionButtonProps) {
  return (
    <button
      type="button"
      onClick={() => setOpen(!open)}
      className="flex w-full min-w-0 items-center justify-between gap-3 rounded-lg px-4 py-3 text-sm font-bold text-slate-200 transition hover:bg-white/10 hover:text-white"
      title={title}
    >
      <span className="flex min-w-0 items-center gap-3">
        <span className="shrink-0 text-slate-300">
          {icon}
        </span>
        <span className="min-w-0 truncate">
          {title}
        </span>
      </span>
      {open ? (
        <ChevronDown
          size={17}
          className="shrink-0 text-slate-400"
        />
      ) : (
        <ChevronRight
          size={17}
          className="shrink-0 text-slate-400"
        />
      )}
    </button>
  );
}
